def parse_and_evaluate(user_program):
    program = parse(user_program)
    implicit_top_level_block = make_block(program)
    return evaluate(implicit_top_level_block,
                    the_global_environment)

parse_and_evaluate("""
def factorial(n):
    return 1 if n == 1 else n * factorial(n - 1)
factorial(5)
""")

parse_and_evaluate("""
def append(xs, ys):
    return ys if is_null(xs) else pair(head(xs), append(tail(xs), ys))
tail(append(list("a", "b"), list("c", "d")))
""")

parse_and_evaluate("""
def map(f, xs):
    return None if is_null(xs) else pair(f(head(xs)), map(f, tail(xs)))
tail(map(lambda x: x + 1, list(1, 2, 3, 4)))
""")
